starterCode:
always @(*) begin
  if (sel) y = a;
end

solution:
always @(*) begin
  if (sel) y = a;
  else     y = b;
end

starterCode:
always @(posedge clk) begin
  a = b;
  b = a;
end

solution:
always @(posedge clk) begin
  a <= b;
  b <= a;
end

always @(posedge clk or negedge rst_n) begin
